import {
  select,
  scaleOrdinal,
  pie,
  arc,
} from "d3"

export default class Donut extends HTMLElement {
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    shadowRoot.innerHTML = `
      <style>
        :host {
          display: flex;
          align-items: center;
          justify-content: center;
          height: 400px;
        }
        svg {
          width: 100%;
          height: 100%;
        }
        text {
          font-family: var(--font-family);
          font-size: 10px;
          fill: var(--text-secondary);
        }
        #root {
          width: fit-content;
          height: fit-content;
          display: flex;
        }
        .inner-circle {
          fill: var(--text-primary);
        }
        .text-anchor {
          font-size: 16px;
          font-weight: 500;
          fill: #ffffff;
        }
        .type {
          font-size: 20px;
          fill: var(--text-tertiary);
        }
        .years {
          font-size: 50px;
          fill: var(--text-tertiary);
        }
      </style>
      <div id="root"></div>
    `
  }

  connectedCallback() {
    this.classList.add("hydrated")
    this.render()
  }

  static get observedAttributes() {
    return ['data', 'height', 'width', 'no-default-event', 'legend', 'colors', 'legend-right'];
  }

  attributeChangedCallback(name, oldValue, newValue) {
    this.render()
  }

  render = () => {
    const root = this.shadowRoot?.querySelector("#root")
    if (!this.shadowRoot || !root) return
    root.innerHTML = ""
    const _width = ~~this.getAttribute("width") 
    const _height = ~~this.getAttribute("height")
    const _legend = this.hasAttribute("legend")
    const _colors = JSON.parse(this.getAttribute("colors"))
    const data = JSON.parse(this.getAttribute("data"))
    if (!data) return
    // set the dimensions and margins of the graph
    const margin = 80
    const height = _height || 400
    const width = _width || 400

    // append the svg object to the body of the page

    const extraX = this.hasAttribute("legend-right") ? 30 : 0
    const svg = select(root)
      .append("svg")
      .attr("width", width + "px")
      .attr("height", height + "px")
      .attr("viewBox", `0 0 ${height} ${width}`)
      .attr("preserveAspectRatio", "xMinYMin")
      .append("g")
      .attr("transform", `translate(${width / 2 - extraX}, ${height / 2})`);

    const radius = Math.min(width, height) / 2 - margin

    // color palette
    const colors = Array.isArray(_colors) ? _colors :["#011f4b", "#03396c", "#005b96", "#6497b1", "#b3cde0", "#4682A9"]
    const color = scaleOrdinal()
      .domain(data)
      .range(colors)


    const _pie = pie()
      .value(d => + d.value)
      .sort(null)

    const dataPrepared = _pie(data)

    const _arc = arc()
      .innerRadius(radius / 2.0)
      .outerRadius(radius)

    data.forEach(function (d) {
      d.value = +d.value;
      d.enabled = true;
    });

    const self = this
    const noDefaultEvent = this.hasAttribute("no-default-event")
    const handleMouseOver = function (e, d) {
      select(this).style("cursor", "pointer")

      if (noDefaultEvent) {
        const event = new CustomEvent("app-mouseover", {
          detail: {
            root,
            data: d,
            select,
            self,
            color,
            event: e
          },
        });
        self.dispatchEvent(event)
        return
      }
      // default mouseover
      const innerText = root.querySelector(".inner-circle")
      const g = select(innerText)
        .append("g")
        .attr("class", "text-group");

      g.append("text")
        .attr("class", "text text-secondary type")
        .text(`${d.data.type}`)
        .attr('text-anchor', 'middle')
        .attr('dy', '-0.8em');

      g.append("text")
        .attr("class", "text text-secondary years")
        .text(`${d.data.value}y`)
        .attr('text-anchor', 'middle')
        .attr('dy', '0.6em');
    }
    const handleMouseOut = function (e, d) {
      select(this).style("cursor", "none")

      if (noDefaultEvent) {
        const event = new CustomEvent("app-mouseout", {
          detail: {
            root,
            data: d,
            select,
            self,
            color,
            event: e
          },
        });
        self.dispatchEvent(event)
        return
      }
      // default mouseout
      const innerText = root.querySelector(".inner-circle .text-group")
      select(innerText).remove()
    }
    svg
      .selectAll('path')
      .data(dataPrepared)
      .join('path')
      .attr('d', _arc)
      .attr('fill', d => color(d.data.type))
      .attr("stroke", "var(--background-primary)")
      .style("stroke-width", "1px")
      .on("mouseover", handleMouseOver)
      .on("mouseout", handleMouseOut)
      .on('mousemove', (e, d) => {
        if (noDefaultEvent) {
          const event = new CustomEvent("app-mousemove", {
            detail: {
              root,
              data: d,
              select,
              self,
              color,
              event: e,
            },
          });
          self.dispatchEvent(event)
          return
        }
      })

    svg
      .append("g")
      .attr("dy", "0.5em")
      .style("font-size", "16px")
      .style("text-anchor", "middle")
      .attr("class", "inner-circle")

    _legend && this.renderLegends({ svg, data, color, height, margin })
  }

  renderLegends = ({ svg, data, color, height, margin }) => {
    const legend = svg.selectAll(".legend")
      .data(data)
      .enter().append("g")
      .attr("class", "legend");

    let xPosition
    let yPosition
    if (this.hasAttribute('legend-right')) {
      xPosition = margin * 1.5 + 20
      yPosition = (_, i) => i * 20
    } else {
      xPosition = -margin / 2
      yPosition = (_, i) => 150 + i * 20
    }
    legend.append("circle")
      .attr("cx", () => xPosition + 20)
      .attr("cy", yPosition)
      .attr("r", 5)
      .attr('fill', d => color(d.type))

    legend.append("text")
      .attr("x", () => xPosition + 30)
      .attr("y", yPosition)
      .attr("dy", ".35em")
      .style("text-anchor", "start")
      .style("fill", "var(--text-tertiary)")
      .style("font-size", "10px")
      .text((d) => {
        return d.type
      });
  }
}
